// Normalize each Shopify order into an enriched shape
// Keeps raw data + adds parsed fields + computed flags

const orders = $input.all();

return orders.map(item => {
  const order = item.json;

  // Numeric parsing (CSV gives us strings)
  const subtotal = parseFloat(order.subtotal_price) || 0;
  const discount = parseFloat(order.total_discounts) || 0;
  const shipping = parseFloat(order.shipping_price) || 0;
  const tax = parseFloat(order.total_tax) || 0;
  const total = parseFloat(order.total_price) || 0;
  const refunded = parseFloat(order.refunded_amount) || 0;

  // Date in YYYY-MM-DD for easier grouping later
  const date = new Date(order.created_at).toISOString().split('T')[0];

  // Tags as array (CSV stores them comma-separated)
  const tags = (order.tags || '').split(',').filter(t => t.length > 0);

  return {
    json: {
      // Source identification
      source: 'shopify',
      transaction_id: order.order_id,
      transaction_name: order.name,
      match_key: order.order_id,

      // Time
      date,
      created_at: order.created_at,

      // Financial
      currency: order.currency,
      subtotal,
      discount,
      shipping,
      tax,
      total,
      refunded,
      net_revenue: subtotal - discount,

      // Status flags
      is_refunded: refunded > 0,
      is_partially_refunded: order.financial_status === 'partially_refunded',
      is_voided: order.financial_status === 'voided',

      // Customer
      email: order.email,
      customer_name: `${order.first_name} ${order.last_name}`.trim(),
      shipping_country: order.shipping_country,

      // Channel metadata
      gateway: order.gateway,
      source_channel: order.source_name,
      is_subscription: tags.includes('subscription'),
      is_returning: tags.includes('returning_customer'),
      has_chargeback: tags.includes('chargeback_dispute'),
      discount_code: order.discount_code || null,
      tags,

      // Preserve original row for audit trail
      raw: order,
    },
  };
});

const items = $input.all();

return items.map(item => {
  const row = item.json;
  const quantity = parseInt(row.quantity) || 0;
  const lineTotal = parseFloat(row.line_total) || 0;
  const lineCogs = parseFloat(row.line_cogs) || 0;

  return {
    json: {
      source: 'shopify_lines',
      transaction_id: `${row.order_id}_${row.sku}`,
      match_key: row.order_id,
      order_id: row.order_id,
      order_name: row.order_name,
      sku: row.sku,
      product_title: row.product_title,
      quantity,
      price: parseFloat(row.price) || 0,
      line_total: lineTotal,
      cogs_per_unit: parseFloat(row.cogs_per_unit) || 0,
      line_cogs: lineCogs,
      line_margin: lineTotal - lineCogs,
      line_margin_pct: lineTotal > 0 ? (lineTotal - lineCogs) / lineTotal : 0,
      raw: row,
    },
  };
});

const txns = $input.all();

return txns.map(item => {
  const row = item.json;
  const date = new Date(row.created).toISOString().split('T')[0];

  let normalizedType = 'unknown';
  if (row.type === 'charge') normalizedType = 'revenue';
  else if (row.type === 'refund') normalizedType = 'refund';
  else if (row.type === 'adjustment' && row.status === 'lost') normalizedType = 'chargeback';
  else if (row.type === 'adjustment') normalizedType = 'fee';

  return {
    json: {
      source: 'stripe',
      transaction_id: row.id,
      match_key: row.shopify_order_id,
      type: row.type,
      normalized_type: normalizedType,
      date,
      created_at: row.created,
      amount: parseFloat(row.amount) || 0,
      fee: parseFloat(row.fee) || 0,
      net: parseFloat(row.net) || 0,
      currency: (row.currency || '').toUpperCase(),
      stripe_object_id: row.source,
      shopify_order_id: row.shopify_order_id,
      shopify_order_name: row.shopify_order_name,
      customer_email: row.customer_email,
      status: row.status,
      is_charge: row.type === 'charge',
      is_refund: row.type === 'refund',
      is_dispute: row.type === 'adjustment',
      is_lost_dispute: row.status === 'lost',
      raw: row,
    },
  };
});

const rows = $input.all();

const glCategory = (desc) => {
  const d = (desc || '').toLowerCase();
  if (d.includes('principal')) return 'revenue';
  if (d.includes('tax')) return 'sales_tax';
  if (d === 'commission' || d === 'refundcommission') return d === 'refundcommission' ? 'refund_commission' : 'marketplace_commission';
  if (d.includes('fbaperunitfulfillmentfee')) return 'fba_fulfillment_fee';
  if (d.includes('storage') && d.includes('long-term')) return 'fba_long_term_storage';
  if (d.includes('storage')) return 'fba_storage_fee';
  if (d.includes('advertising')) return 'ad_spend';
  return 'other';
};

return rows.map(item => {
  const row = item.json;
  const ttype = row['transaction-type'];
  const adesc = row['amount-description'];

  return {
    json: {
      source: 'amazon',
      transaction_id: `${row['settlement-id']}_${row['adjustment-id'] || row['order-id'] || 'n'}_${adesc}_${row.sku || 'na'}_${row['posted-date-time']}`,
      match_key: row['settlement-id'],
      settlement_id: row['settlement-id'],
      settlement_start: row['settlement-start-date'],
      settlement_end: row['settlement-end-date'],
      deposit_date: row['deposit-date'],
      posted_date: row['posted-date'],
      order_id: row['order-id'] || '',
      transaction_type: ttype,
      amount_description: adesc,
      gl_category: glCategory(adesc),
      amount: parseFloat(row.amount) || 0,
      currency: 'USD',
      sku: row.sku || null,
      quantity: parseInt(row['quantity-purchased']) || 0,
      is_order: ttype === 'Order',
      is_refund: ttype === 'Refund',
      is_storage_fee: ttype === 'Storage Fee',
      is_ad_spend: ttype === 'Cost of Advertising',
      raw: row,
    },
  };
});

const orders = $input.all();

return orders.map(item => {
  const row = item.json;
  const created = new Date(row.created_at);
  const date = created.toISOString().split('T')[0];
  const dow = created.getDay();
  const daysToSun = dow === 0 ? 0 : 7 - dow;
  const weekEnding = new Date(created);
  weekEnding.setDate(created.getDate() + daysToSun);
  const weekEndingStr = weekEnding.toISOString().split('T')[0];

  return {
    json: {
      source: 'faire',
      transaction_id: row.order_id,
      match_key: weekEndingStr,
      date,
      created_at: row.created_at,
      ship_date: row.ship_date,
      payment_due_date: row.payment_due_date,
      week_ending: weekEndingStr,
      subtotal_wholesale: parseFloat(row.subtotal_wholesale) || 0,
      commission_rate: parseFloat(row.faire_commission_rate) || 0,
      commission: parseFloat(row.faire_commission) || 0,
      net_payable: parseFloat(row.net_payable_to_brand) || 0,
      boutique_name: row.boutique_name,
      boutique_state: row.boutique_state,
      total_units: parseInt(row.total_units) || 0,
      status: row.status,
      is_paid: row.payment_received === 'true',
      is_first_order: row.is_first_order === 'true',
      raw: row,
    },
  };
});

const txns = $input.all();

const classify = (counterparty) => {
  const c = (counterparty || '').toUpperCase();
  if (c.includes('SHOPIFY PAYMENTS')) return { channel: 'shopify', txn_class: 'deposit', expected_source: 'stripe_daily' };
  if (c.includes('AMAZON')) return { channel: 'amazon', txn_class: 'deposit', expected_source: 'amazon_settlement' };
  if (c.includes('FAIRE')) return { channel: 'faire', txn_class: 'deposit', expected_source: 'faire_weekly' };
  if (c.includes('PAYPAL')) return { channel: 'paypal', txn_class: 'deposit', expected_source: 'paypal_weekly' };
  if (c.includes('KLARNA')) return { channel: 'klarna', txn_class: 'deposit', expected_source: 'klarna_weekly' };
  if (c.includes('SPA') || c.includes('WELLNESS')) return { channel: 'wholesale_direct', txn_class: 'deposit', expected_source: 'wholesale_invoice' };
  if (c.includes('SHIPBOB')) return { channel: 'ops', txn_class: 'expense', gl_category: 'fulfillment' };
  if (c.includes('GUSTO')) return { channel: 'ops', txn_class: 'expense', gl_category: 'payroll' };
  if (c.includes('META') || c.includes('GOOGLE ADS') || c.includes('LIFTOFF')) return { channel: 'ops', txn_class: 'expense', gl_category: 'advertising' };
  if (c.includes('MERIDIAN')) return { channel: 'ops', txn_class: 'expense', gl_category: 'inventory_purchase' };
  if (c.includes('CFO') || c.includes('DAVID PARK')) return { channel: 'ops', txn_class: 'expense', gl_category: 'professional_services' };
  if (c.includes('MERCURY CC')) return { channel: 'ops', txn_class: 'transfer', gl_category: 'credit_card_payment' };
  if (c.match(/SHOPIFY|KLAVIYO|RECHARGE|GORGIAS|JUNIP|COGSY|QBO|INTUIT/)) return { channel: 'ops', txn_class: 'expense', gl_category: 'saas' };
  return { channel: 'unknown', txn_class: 'unknown', gl_category: 'review' };
};

return txns.map(item => {
  const row = item.json;
  const cls = classify(row.counterparty);

  return {
    json: {
      source: 'mercury',
      transaction_id: row.transaction_id,
      match_key: row.posted_at,
      posted_at: row.posted_at,
      date: row.posted_at,
      amount: parseFloat(row.amount) || 0,
      type: row.type,
      counterparty: row.counterparty,
      description: row.description,
      running_balance: parseFloat(row.running_balance) || 0,
      channel: cls.channel,
      txn_class: cls.txn_class,
      gl_category: cls.gl_category || null,
      expected_source: cls.expected_source || null,
      is_deposit: row.type === 'credit',
      is_expense: row.type === 'debit',
      raw: row,
    },
  };
});

// Pull from both connected inputs (Shopify orders + Stripe)
// Differentiate by the 'source' tag each normalizer added
const allItems = $input.all();

const shopifyOrders = allItems.filter(item => item.json.source === 'shopify');
const stripeTxns = allItems.filter(item => item.json.source === 'stripe');

// Build a lookup index of Stripe transactions by Shopify order ID
const stripeByOrder = {};
stripeTxns.forEach(item => {
  const txn = item.json;
  const orderId = txn.shopify_order_id;
  if (!orderId) return;
  if (!stripeByOrder[orderId]) {
    stripeByOrder[orderId] = { charges: [], refunds: [], disputes: [] };
  }
  if (txn.is_charge) stripeByOrder[orderId].charges.push(txn);
  else if (txn.is_refund) stripeByOrder[orderId].refunds.push(txn);
  else if (txn.is_dispute) stripeByOrder[orderId].disputes.push(txn);
});

// Filter to Shopify Payments orders only, then enrich
return shopifyOrders
  .filter(item => item.json.gateway === 'shopify_payments')
  .map(item => {
    const order = item.json;
    const stripe = stripeByOrder[order.transaction_id] || { charges: [], refunds: [], disputes: [] };

    const stripeGross = stripe.charges.reduce((s, c) => s + c.amount, 0);
    const stripeFee = stripe.charges.reduce((s, c) => s + c.fee, 0);
    const stripeNet = stripe.charges.reduce((s, c) => s + c.net, 0);
    const stripeRefunded = stripe.refunds.reduce((s, r) => s + Math.abs(r.amount), 0);
    const stripeDisputeFees = stripe.disputes.reduce((s, d) => s + (d.fee || 0), 0);

    return {
      json: {
        ...order,
        has_stripe_match: stripe.charges.length > 0,
        stripe_charge_count: stripe.charges.length,
        stripe_refund_count: stripe.refunds.length,
        stripe_dispute_count: stripe.disputes.length,
        stripe_gross: Math.round(stripeGross * 100) / 100,
        stripe_fee: Math.round(stripeFee * 100) / 100,
        stripe_net: Math.round(stripeNet * 100) / 100,
        stripe_refunded: Math.round(stripeRefunded * 100) / 100,
        stripe_dispute_fees: Math.round(stripeDisputeFees * 100) / 100,
        stripe_charge_ids: stripe.charges.map(c => c.stripe_object_id),
        stripe_refund_ids: stripe.refunds.map(r => r.stripe_object_id),
      },
    };
  });

// Aggregate Amazon settlement rows into settlement-level totals
// Each settlement becomes one journal entry candidate

const rows = $input.all();
const settlements = {};

rows.forEach(item => {
  const r = item.json;
  const sid = r.settlement_id;
  if (!sid) return;

  if (!settlements[sid]) {
    settlements[sid] = {
      settlement_id: sid,
      settlement_start: r.settlement_start,
      settlement_end: r.settlement_end,
      deposit_date: r.deposit_date,
      // GL-allocated buckets
      revenue: 0,
      sales_tax: 0,
      marketplace_commission: 0,
      refund_commission: 0,
      fba_fulfillment_fee: 0,
      fba_storage_fee: 0,
      fba_long_term_storage: 0,
      ad_spend: 0,
      refund_principal: 0,
      other: 0,
      // Counts
      order_count: 0,
      refund_count: 0,
      row_count: 0,
      // Net deposit
      total_net: 0,
    };
  }

  const s = settlements[sid];
  const amt = r.amount;
  s.total_net += amt;
  s.row_count += 1;

  if (r.gl_category === 'revenue' && r.is_order) {
    s.revenue += amt;
    s.order_count += 1;
  } else if (r.gl_category === 'revenue' && r.is_refund) {
    s.refund_principal += amt;
    s.refund_count += 1;
  } else if (r.gl_category === 'sales_tax') {
    s.sales_tax += amt;
  } else if (r.gl_category === 'marketplace_commission') {
    s.marketplace_commission += amt;
  } else if (r.gl_category === 'refund_commission') {
    s.refund_commission += amt;
  } else if (r.gl_category === 'fba_fulfillment_fee') {
    s.fba_fulfillment_fee += amt;
  } else if (r.gl_category === 'fba_storage_fee') {
    s.fba_storage_fee += amt;
  } else if (r.gl_category === 'fba_long_term_storage') {
    s.fba_long_term_storage += amt;
  } else if (r.gl_category === 'ad_spend') {
    s.ad_spend += amt;
  } else {
    s.other += amt;
  }
});

// Round monetary values and emit one item per settlement
return Object.values(settlements).map(s => ({
  json: {
    source: 'amazon_aggregated',
    settlement_id: s.settlement_id,
    settlement_start: s.settlement_start,
    settlement_end: s.settlement_end,
    deposit_date: s.deposit_date,
    revenue: Math.round(s.revenue * 100) / 100,
    sales_tax: Math.round(s.sales_tax * 100) / 100,
    marketplace_commission: Math.round(s.marketplace_commission * 100) / 100,
    refund_commission: Math.round(s.refund_commission * 100) / 100,
    fba_fulfillment_fee: Math.round(s.fba_fulfillment_fee * 100) / 100,
    fba_storage_fee: Math.round(s.fba_storage_fee * 100) / 100,
    fba_long_term_storage: Math.round(s.fba_long_term_storage * 100) / 100,
    ad_spend: Math.round(s.ad_spend * 100) / 100,
    refund_principal: Math.round(s.refund_principal * 100) / 100,
    other: Math.round(s.other * 100) / 100,
    order_count: s.order_count,
    refund_count: s.refund_count,
    row_count: s.row_count,
    total_net: Math.round(s.total_net * 100) / 100,
  },
}));

// Aggregate Faire wholesale into weekly payouts
// Only orders marked is_paid = true contribute to bank deposits
const orders = $input.all();

const weekly = {};

orders
  .filter(item => item.json.is_paid)
  .forEach(item => {
    const o = item.json;
    const week = o.week_ending;
    if (!weekly[week]) {
      weekly[week] = {
        week_ending: week,
        gross_wholesale: 0,
        total_commission: 0,
        net_payout: 0,
        order_count: 0,
        boutiques: new Set(),
      };
    }
    weekly[week].gross_wholesale += o.subtotal_wholesale;
    weekly[week].total_commission += o.commission;
    weekly[week].net_payout += o.net_payable;
    weekly[week].order_count += 1;
    weekly[week].boutiques.add(o.boutique_name);
  });

return Object.values(weekly)
  .sort((a, b) => a.week_ending.localeCompare(b.week_ending))
  .map(w => ({
    json: {
      source: 'faire_aggregated',
      week_ending: w.week_ending,
      gross_wholesale: Math.round(w.gross_wholesale * 100) / 100,
      total_commission: Math.round(w.total_commission * 100) / 100,
      net_payout: Math.round(w.net_payout * 100) / 100,
      order_count: w.order_count,
      boutique_count: w.boutiques.size,
      boutiques: Array.from(w.boutiques),
    },
  }));

// Aggregate PayPal and Klarna orders by week
// These gateways batch-deposit weekly, unlike Stripe's daily payouts
const orders = $input.all();

const aggregate = (gateway, feeRate) => {
  const weekly = {};

  orders
    .filter(item => item.json.gateway === gateway && item.json.currency === 'USD')
    .forEach(item => {
      const o = item.json;
      const created = new Date(o.created_at);
      const dow = created.getDay();
      const daysToSun = dow === 0 ? 0 : 7 - dow;
      const weekEnding = new Date(created);
      weekEnding.setDate(created.getDate() + daysToSun);
      const week = weekEnding.toISOString().split('T')[0];

      if (!weekly[week]) {
        weekly[week] = {
          week_ending: week,
          gross_revenue: 0,
          refunds: 0,
          net_revenue: 0,
          order_count: 0,
        };
      }
      weekly[week].gross_revenue += o.total;
      weekly[week].refunds += o.refunded;
      weekly[week].net_revenue += (o.total - o.refunded);
      weekly[week].order_count += 1;
    });

  return Object.values(weekly).map(w => ({
    json: {
      source: `${gateway}_aggregated`,
      gateway,
      week_ending: w.week_ending,
      gross_revenue: Math.round(w.gross_revenue * 100) / 100,
      refunds: Math.round(w.refunds * 100) / 100,
      net_revenue: Math.round(w.net_revenue * 100) / 100,
      expected_deposit: Math.round(w.net_revenue * (1 - feeRate) * 100) / 100,
      fee_rate: feeRate,
      order_count: w.order_count,
    },
  }));
};

const paypal = aggregate('paypal', 0.034);   // PayPal ~3.4%
const klarna = aggregate('klarna', 0.055);   // Klarna BNPL ~5.5%

return [...paypal, ...klarna]
  .sort((a, b) => {
    if (a.json.gateway !== b.json.gateway) return a.json.gateway.localeCompare(b.json.gateway);
    return a.json.week_ending.localeCompare(b.json.week_ending);
  });

// Aggregate Stripe USD transactions by deposit date (T+2 from created)
// This is what Mercury's daily SHOPIFY PAYMENTS deposits represent
const txns = $input.all();
const daily = {};

txns.forEach(item => {
  const t = item.json;
  if ((t.currency || '').toUpperCase() !== 'USD') return; // GBP order excluded

  const created = new Date(t.created_at);
  const deposit = new Date(created);
  deposit.setDate(created.getDate() + 2);
  const depositDate = deposit.toISOString().split('T')[0];

  if (!daily[depositDate]) {
    daily[depositDate] = {
      deposit_date: depositDate,
      charge_count: 0,
      refund_count: 0,
      dispute_count: 0,
      gross: 0,
      fees: 0,
      net: 0,
    };
  }

  daily[depositDate].gross += t.amount;
  daily[depositDate].fees += t.fee;
  daily[depositDate].net += t.net;

  if (t.is_charge) daily[depositDate].charge_count += 1;
  else if (t.is_refund) daily[depositDate].refund_count += 1;
  else if (t.is_dispute) daily[depositDate].dispute_count += 1;
});

return Object.values(daily)
  .sort((a, b) => a.deposit_date.localeCompare(b.deposit_date))
  .map(d => ({
    json: {
      source: 'shopify_payments_daily',
      deposit_date: d.deposit_date,
      charge_count: d.charge_count,
      refund_count: d.refund_count,
      dispute_count: d.dispute_count,
      gross: Math.round(d.gross * 100) / 100,
      fees: Math.round(d.fees * 100) / 100,
      net: Math.round(d.net * 100) / 100,
    },
  }));

// Multi-input Code nodes in n8n fire once per upstream branch.
// Gate to the run that contains Mercury, ignore others, pull aggregates via $() refs.

const inputItems = $input.all();
const hasMercury = inputItems.some(i => i.json.source === 'mercury');
if (!hasMercury) return [];

// Pull all sources via explicit references — they're cached after their nodes execute
const mercuryRows  = $('Normalize Mercury').all();
const shopifyDaily = $('Aggregate Shopify Payments Daily').all();
const amazonAgg    = $('Aggregate Amazon Settlements').all();
const faireAgg     = $('Aggregate Faire Weekly').all();
const paypalKlarna = $('Aggregate PayPal & Klarna Weekly').all();
const paypalAgg = paypalKlarna.filter(i => i.json.source === 'paypal_aggregated');
const klarnaAgg = paypalKlarna.filter(i => i.json.source === 'klarna_aggregated');

const classify = (actual, expected) => {
  if (expected === null || expected === undefined) return { status: 'UNMATCHED', variance: null, variance_pct: null };
  const variance = actual - expected;
  const absVar = Math.abs(variance);
  const variancePct = expected !== 0 ? Math.abs(variance / expected) : 0;
  if (absVar < 0.50) return { status: 'MATCHED', variance, variance_pct: variancePct };
  if (variancePct < 0.005) return { status: 'PARTIAL', variance, variance_pct: variancePct };
  return { status: 'DISCREPANCY', variance, variance_pct: variancePct };
};

const findWeekly = (depositDate, aggregates, amountField) => {
  const dd = new Date(depositDate);
  const candidate = aggregates
    .map(a => ({ ...a.json, _diff: dd - new Date(a.json.week_ending) }))
    .filter(a => a._diff >= 0 && a._diff <= 7 * 86400000)
    .sort((a, b) => a._diff - b._diff)[0];
  return candidate ? { amount: candidate[amountField], id: candidate.week_ending } : null;
};

return mercuryRows.map(item => {
  const m = item.json;
  let expectedAmount = null;
  let matchedSourceId = null;
  let matchedSourceType = null;
  let matchResult = { status: 'NOT_RECONCILED', variance: null, variance_pct: null };

  if (m.is_deposit) {
    if (m.channel === 'shopify') {
      const match = shopifyDaily.find(s => s.json.deposit_date === m.posted_at);
      if (match) {
        expectedAmount = match.json.net;
        matchedSourceId = match.json.deposit_date;
        matchedSourceType = 'shopify_payments_daily';
      }
    } else if (m.channel === 'amazon') {
      const match = amazonAgg.find(a => a.json.deposit_date === m.posted_at);
      if (match) {
        expectedAmount = match.json.total_net;
        matchedSourceId = match.json.settlement_id;
        matchedSourceType = 'amazon_settlement';
      }
    } else if (m.channel === 'faire') {
      const found = findWeekly(m.posted_at, faireAgg, 'net_payout');
      if (found) { expectedAmount = found.amount; matchedSourceId = found.id; matchedSourceType = 'faire_weekly'; }
    } else if (m.channel === 'paypal') {
      const found = findWeekly(m.posted_at, paypalAgg, 'expected_deposit');
      if (found) { expectedAmount = found.amount; matchedSourceId = found.id; matchedSourceType = 'paypal_weekly'; }
    } else if (m.channel === 'klarna') {
      const found = findWeekly(m.posted_at, klarnaAgg, 'expected_deposit');
      if (found) { expectedAmount = found.amount; matchedSourceId = found.id; matchedSourceType = 'klarna_weekly'; }
    } else if (m.channel === 'wholesale_direct') {
      expectedAmount = m.amount;
      matchedSourceType = 'wholesale_invoice';
    }
    matchResult = classify(m.amount, expectedAmount);
  }

  return {
    json: {
      ...m,
      match_status: matchResult.status,
      expected_amount: expectedAmount !== null ? Math.round(expectedAmount * 100) / 100 : null,
      actual_amount: m.amount,
      variance: matchResult.variance !== null ? Math.round(matchResult.variance * 100) / 100 : null,
      variance_pct: matchResult.variance_pct !== null ? Math.round(matchResult.variance_pct * 10000) / 100 : null,
      matched_source_id: matchedSourceId,
      matched_source_type: matchedSourceType,
    },
  };
});

// Detect anomalies across all sources
// Pulls reconciled rows + cross-period candidates + FX cases + chargebacks
const inputItems = $input.all();
const hasReconciled = inputItems.some(i => 'match_status' in i.json);
if (!hasReconciled) return [];

const reconciled = $('Reconcile Mercury vs Sources').all();
const amazonAgg = $('Aggregate Amazon Settlements').all();
const shopifyOrders = $('Normalize Shopify Orders').all();
const stripeTxns = $('Normalize Stripe').all();

const anomalies = [];

// 1. Mercury reconciliation discrepancies (already detected; we just classify severity)
reconciled.forEach(item => {
  const r = item.json;
  if (r.match_status === 'DISCREPANCY' || r.match_status === 'UNMATCHED') {
    const varAbs = Math.abs(r.variance || 0);
    const varPct = r.variance_pct || 0;
    let severity = 'low';
    if (varAbs > 1000 || varPct > 50) severity = 'high';
    else if (varAbs > 200 || varPct > 10) severity = 'medium';

    let recommendation = 'Investigate source data for missing or duplicate transactions.';
    if (r.channel === 'faire') {
      recommendation = 'Faire pays on delivery date, not order date. Use Faire payout report as source of truth, not derived weekly aggregates.';
    } else if (r.channel === 'paypal' || r.channel === 'klarna') {
      recommendation = `${r.channel.toUpperCase()} batch timing is naturally lumpy. Verify against ${r.channel} settlement export and adjust expected calculation.`;
    }

    anomalies.push({
      anomaly_id: `MERCURY_${r.transaction_id}`,
      anomaly_type: r.match_status === 'UNMATCHED' ? 'unmatched_deposit' : 'amount_variance',
      severity,
      date: r.posted_at,
      channel: r.channel,
      counterparty: r.counterparty,
      actual: r.amount,
      expected: r.expected_amount,
      variance: r.variance,
      variance_pct: r.variance_pct,
      description: r.description,
      recommendation,
    });
  }
});

// 2. Cross-period fees (Amazon settlement with deposit_date outside reconciliation period)
amazonAgg.forEach(item => {
  const s = item.json;
  const depositMonth = (s.deposit_date || '').substring(0, 7);
  if (depositMonth !== '2026-01' && (s.fba_long_term_storage !== 0 || s.fba_storage_fee !== 0)) {
    const feeAmount = (s.fba_long_term_storage || 0) + (s.fba_storage_fee || 0);
    anomalies.push({
      anomaly_id: `AMZ_${s.settlement_id}_CROSS_PERIOD`,
      anomaly_type: 'cross_period_fee',
      severity: 'high',
      date: s.settlement_end,
      channel: 'amazon',
      counterparty: 'AMAZON SELLER',
      actual: feeAmount,
      expected: null,
      variance: null,
      variance_pct: null,
      description: `Long-term storage fee $${Math.abs(feeAmount).toFixed(2)} on settlement ${s.settlement_id} (deposit ${s.deposit_date}) relates to Q4 2025 inventory`,
      recommendation: `Accrue $${Math.abs(feeAmount).toFixed(2)} back to Q4 2025. Journal entry: DR FBA Long-Term Storage Q4 2025, CR Accrued Expenses. Reverse the accrual when settlement deposits in Feb.`,
    });
  }
});

// 3. Multi-currency orders (need FX revaluation entry)
shopifyOrders.forEach(item => {
  const o = item.json;
  if (o.currency !== 'USD' && parseFloat(o.total) > 0) {
    anomalies.push({
      anomaly_id: `FX_${o.transaction_id}`,
      anomaly_type: 'multi_currency',
      severity: 'medium',
      date: o.date,
      channel: 'shopify',
      counterparty: `${o.transaction_name} (${o.shipping_country})`,
      actual: o.total,
      expected: null,
      variance: null,
      variance_pct: null,
      description: `Order ${o.transaction_name} in ${o.currency} — needs FX revaluation between transaction and deposit dates`,
      recommendation: `Apply ${o.currency}/USD rate at transaction date for revenue recognition, and at deposit settlement date for cash. Difference posts to FX Gain/Loss.`,
    });
  }
});

// 4. Chargebacks (lost disputes — revenue reversal + fee expense)
const chargebacks = {};
stripeTxns.forEach(item => {
  const t = item.json;
  if (t.is_lost_dispute || (t.type === 'adjustment' && t.status === 'lost')) {
    if (!chargebacks[t.shopify_order_id]) {
      chargebacks[t.shopify_order_id] = {
        order_id: t.shopify_order_id,
        order_name: t.shopify_order_name,
        date: t.date,
        amount: 0,
        fees: 0,
      };
    }
    chargebacks[t.shopify_order_id].amount += Math.abs(t.amount);
    chargebacks[t.shopify_order_id].fees += t.fee || 0;
  }
});

Object.values(chargebacks).forEach(cb => {
  anomalies.push({
    anomaly_id: `CB_${cb.order_id}`,
    anomaly_type: 'chargeback',
    severity: 'high',
    date: cb.date,
    channel: 'shopify',
    counterparty: cb.order_name,
    actual: -(cb.amount + cb.fees),
    expected: null,
    variance: null,
    variance_pct: null,
    description: `Chargeback dispute on ${cb.order_name}: $${cb.amount.toFixed(2)} withdrawn + $${cb.fees.toFixed(2)} dispute fee`,
    recommendation: `Reverse revenue: DR Chargebacks (revenue contra) $${cb.amount.toFixed(2)}, DR Chargeback Fees $${cb.fees.toFixed(2)}, CR Cash $${(cb.amount + cb.fees).toFixed(2)}.`,
  });
});

// Sort by severity, then by date
const severityOrder = { high: 0, medium: 1, low: 2 };
anomalies.sort((a, b) => {
  const s = severityOrder[a.severity] - severityOrder[b.severity];
  if (s !== 0) return s;
  return (a.date || '').localeCompare(b.date || '');
});

return anomalies.map(a => ({ json: a }));

// Generate journal entry candidates for posting to QuickBooks
// All entries are guaranteed to balance (debits = credits)

const inputItems = $input.all();
const hasMercury = inputItems.some(i => i.json.source === 'mercury' && 'match_status' in i.json);
if (!hasMercury) return [];

// Safe $() that returns [] instead of throwing
const tryAll = (name) => {
  try {
    return $(name).all();
  } catch (e) {
    return [];
  }
};

const shopifyDaily = tryAll('Aggregate Shopify Payments Daily');
const amazonAgg    = tryAll('Aggregate Amazon Settlements');
const faireAgg     = tryAll('Aggregate Faire Weekly');
const paypalKlarna = tryAll('Aggregate PayPal & Klarna Weekly');

if (!shopifyDaily.length && !amazonAgg.length && !faireAgg.length && !paypalKlarna.length) {
  return [{ json: { warning: 'No aggregates accessible. Run Execute Workflow (bottom red button) to populate.' } }];
}

// Helper: build a journal entry with cleaned/rounded lines + balance check
const buildJE = (id, date, description, lines) => {
  const cleaned = lines
    .filter(l => Math.abs(l.debit || 0) > 0.005 || Math.abs(l.credit || 0) > 0.005)
    .map(l => ({
      account: l.account,
      debit: Math.round((l.debit || 0) * 100) / 100,
      credit: Math.round((l.credit || 0) * 100) / 100,
    }));
  const totalDebits = cleaned.reduce((s, l) => s + l.debit, 0);
  const totalCredits = cleaned.reduce((s, l) => s + l.credit, 0);
  return {
    je_id: id,
    je_date: date,
    description,
    lines: cleaned,
    total_debits: Math.round(totalDebits * 100) / 100,
    total_credits: Math.round(totalCredits * 100) / 100,
    balanced: Math.abs(totalDebits - totalCredits) < 0.01,
  };
};

// Helper: add a balancing line if debits ≠ credits
const balanceLines = (lines, account) => {
  const totalD = lines.reduce((s, l) => s + (l.debit > 0 ? l.debit : 0), 0);
  const totalC = lines.reduce((s, l) => s + (l.credit > 0 ? l.credit : 0), 0);
  const variance = totalD - totalC;
  if (Math.abs(variance) > 0.01) {
    if (variance > 0) {
      lines.push({ account, credit: variance });
    } else {
      lines.push({ account, debit: -variance });
    }
  }
  return lines;
};

const journalEntries = [];

// Shopify Payments — daily settlements (with refund fee retention)
shopifyDaily.forEach(item => {
  const d = item.json;
  if (d.net <= 0) return;
  const lines = balanceLines(
    [
      { account: '1000 - Cash (Mercury)', debit: d.net },
      { account: '5100 - Stripe Processing Fees', debit: d.fees },
      { account: '4000 - Revenue - Shopify DTC', credit: d.gross },
    ],
    '5101 - Stripe Refund Fee Retention'
  );
  journalEntries.push(buildJE(
    `JE-SHOPIFY-${d.deposit_date}`,
    d.deposit_date,
    `Shopify Payments daily settlement ${d.deposit_date}`,
    lines
  ));
});

// Amazon — bi-weekly settlements (skip the cross-period anomaly)
amazonAgg.forEach(item => {
  const s = item.json;
  if (s.settlement_id === 'SET-2026-02-11') return;
  const lines = balanceLines(
    [
      { account: '1000 - Cash (Mercury)', debit: s.total_net },
      { account: '5200 - Amazon Marketplace Commission', debit: -s.marketplace_commission },
      { account: '5210 - FBA Fulfillment Fees', debit: -s.fba_fulfillment_fee },
      { account: '5220 - FBA Storage Fees', debit: -s.fba_storage_fee },
      { account: '6100 - Advertising - Amazon Sponsored Products', debit: -s.ad_spend },
      { account: '4015 - Amazon Refunds (contra revenue)', debit: -s.refund_principal },
      { account: '5215 - Amazon Refund Commission Retention', debit: s.refund_commission },
      { account: '4010 - Revenue - Amazon FBA', credit: s.revenue },
      { account: '2100 - Sales Tax Payable', credit: s.sales_tax },
    ],
    '4099 - Marketplace Settlement Rounding'
  );
  journalEntries.push(buildJE(
    `JE-AMAZON-${s.settlement_id}`,
    s.deposit_date,
    `Amazon settlement ${s.settlement_id} (${s.settlement_start} to ${s.settlement_end})`,
    lines
  ));
});

// Faire — weekly wholesale payouts
faireAgg.forEach(item => {
  const f = item.json;
  if (f.net_payout <= 0) return;
  const lines = balanceLines(
    [
      { account: '1000 - Cash (Mercury)', debit: f.net_payout },
      { account: '5300 - Faire Marketplace Commission', debit: f.total_commission },
      { account: '4020 - Revenue - Wholesale (Faire)', credit: f.gross_wholesale },
    ],
    '4099 - Marketplace Settlement Rounding'
  );
  journalEntries.push(buildJE(
    `JE-FAIRE-${f.week_ending}`,
    f.week_ending,
    `Faire wholesale week ending ${f.week_ending}`,
    lines
  ));
});

// PayPal & Klarna — weekly settlements
paypalKlarna.forEach(item => {
  const pk = item.json;
  if (pk.net_revenue <= 0) return;
  const expenseAcct = pk.gateway === 'paypal'
    ? '5110 - PayPal Processing Fees'
    : '5120 - Klarna Processing Fees';
  const revAcct = pk.gateway === 'paypal'
    ? '4001 - Revenue - Shopify DTC (PayPal)'
    : '4002 - Revenue - Shopify DTC (Klarna)';
  const fees = pk.net_revenue - pk.expected_deposit;
  const lines = balanceLines(
    [
      { account: '1000 - Cash (Mercury)', debit: pk.expected_deposit },
      { account: expenseAcct, debit: fees },
      { account: revAcct, credit: pk.net_revenue },
    ],
    '4099 - Marketplace Settlement Rounding'
  );
  journalEntries.push(buildJE(
    `JE-${pk.gateway.toUpperCase()}-${pk.week_ending}`,
    pk.week_ending,
    `${pk.gateway === 'paypal' ? 'PayPal' : 'Klarna'} weekly settlement w/e ${pk.week_ending}`,
    lines
  ));
});

// Sort chronologically and emit
journalEntries.sort((a, b) => a.je_date.localeCompare(b.je_date));
return journalEntries.map(je => ({ json: je }));

// Build the Slack-ready summary message — no dependency on Generate Journal Entries
const inputItems = $input.all();
if (inputItems.length === 0) return [];

const reconciled    = $('Reconcile Mercury vs Sources').all();
const anomalies     = $('Detect Anomalies').all();
const shopifyDaily  = $('Aggregate Shopify Payments Daily').all();
const amazonAgg     = $('Aggregate Amazon Settlements').all();
const faireAgg      = $('Aggregate Faire Weekly').all();
const paypalKlarna  = $('Aggregate PayPal & Klarna Weekly').all();

const count = (arr, fn) => arr.filter(i => fn(i.json)).length;
const sum = (arr, key) => arr.reduce((s, i) => s + (i.json[key] || 0), 0);

// JE count computed directly from aggregates
const jeCount = count(shopifyDaily, d => d.net > 0)
  + count(amazonAgg, s => s.settlement_id !== 'SET-2026-02-11')
  + count(faireAgg, f => f.net_payout > 0)
  + count(paypalKlarna, pk => pk.net_revenue > 0);

const totalMercury = reconciled.length;
const matched = count(reconciled, r => r.match_status === 'MATCHED');
const discrepancy = count(reconciled, r => r.match_status === 'DISCREPANCY' || r.match_status === 'PARTIAL');
const notReconciled = count(reconciled, r => r.match_status === 'NOT_RECONCILED');

const highSeverity = count(anomalies, a => a.severity === 'high');
const mediumSeverity = count(anomalies, a => a.severity === 'medium');
const lowSeverity = count(anomalies, a => a.severity === 'low');
const crossPeriod = count(anomalies, a => a.anomaly_type === 'cross_period_fee');
const chargebacks = count(anomalies, a => a.anomaly_type === 'chargeback');
const multiCurrency = count(anomalies, a => a.anomaly_type === 'multi_currency');

const shopifyRev = sum(shopifyDaily, 'gross');
const amazonRev = sum(amazonAgg, 'revenue');
const faireRev = sum(faireAgg, 'gross_wholesale');
const paypalRev = paypalKlarna.filter(i => i.json.gateway === 'paypal').reduce((s, i) => s + (i.json.gross_revenue || 0), 0);
const klarnaRev = paypalKlarna.filter(i => i.json.gateway === 'klarna').reduce((s, i) => s + (i.json.gross_revenue || 0), 0);
const totalRev = shopifyRev + amazonRev + faireRev + paypalRev + klarnaRev;

const fmt = n => '$' + Math.round(n).toLocaleString('en-US');

const summary = `:receipt: *Sample Brand — January 2026 Reconciliation Complete*

:bar_chart: *Volume*
- ${totalMercury} bank transactions processed
- ${jeCount} journal entries ready for QuickBooks
- ${fmt(totalRev)} gross revenue (Shopify ${fmt(shopifyRev)} / Amazon ${fmt(amazonRev)} / Faire ${fmt(faireRev)} / PayPal ${fmt(paypalRev)} / Klarna ${fmt(klarnaRev)})

:white_check_mark: *Reconciliation*
- ${matched} matched cleanly (${Math.round(matched / totalMercury * 100)}%)
- ${discrepancy} flagged for review
- ${notReconciled} expenses passed through to GL

:warning: *${anomalies.length} anomalies needing review*
- ${highSeverity} HIGH${crossPeriod ? ` — includes ${crossPeriod} cross-period fee (accrue back to Q4 2025)` : ''}${chargebacks ? `\n• ${chargebacks} chargeback dispute — reverse revenue + post fee` : ''}
- ${mediumSeverity} MEDIUM${multiCurrency ? ` — includes ${multiCurrency} multi-currency order needing FX revaluation` : ''}
- ${lowSeverity} LOW

:hourglass_flowing_sand: *Estimated bookkeeper time saved: ~28 hours*
Previously: ~30 hrs/month manual reconciliation. Now: ~2 hrs reviewing the flagged items above.

:file_folder: *Outputs in /files/sample/outputs/*
- journal_entries.csv
- reconciliation_report.csv
- discrepancies.csv`;

return [{
  json: {
    summary_text: summary,
    stats: {
      total_mercury_transactions: totalMercury,
      matched, discrepancy, not_reconciled: notReconciled,
      anomalies_total: anomalies.length,
      anomalies_high: highSeverity, anomalies_medium: mediumSeverity, anomalies_low: lowSeverity,
      cross_period_fees: crossPeriod, chargebacks, multi_currency: multiCurrency,
      journal_entries_count: jeCount,
      total_revenue: Math.round(totalRev * 100) / 100,
    },
  },
}];

// Per-SKU revenue, COGS, gross margin, and revenue share
// Input: Normalize Shopify Line Items (4,903 items)
// Output: 15 SKUs ranked by revenue

const lineItems = $input.all();

const skuStats = {};

lineItems.forEach(item => {
  const li = item.json;
  const sku = li.sku;
  if (!skuStats[sku]) {
    skuStats[sku] = {
      sku,
      product_title: li.product_title,
      units_sold: 0,
      revenue: 0,
      cogs: 0,
      orders_with_sku: new Set(),
    };
  }
  skuStats[sku].units_sold += li.quantity;
  skuStats[sku].revenue += li.line_total;
  skuStats[sku].cogs += li.line_cogs;
  skuStats[sku].orders_with_sku.add(li.order_id);
});

const totalRevenue = Object.values(skuStats).reduce((s, sk) => s + sk.revenue, 0);

return Object.values(skuStats)
  .map(s => {
    const grossMargin = s.revenue - s.cogs;
    const marginPct = s.revenue > 0 ? grossMargin / s.revenue : 0;
    const revenueSharePct = totalRevenue > 0 ? s.revenue / totalRevenue : 0;
    return {
      sku: s.sku,
      product_title: s.product_title,
      units_sold: s.units_sold,
      orders_containing: s.orders_with_sku.size,
      revenue: Math.round(s.revenue * 100) / 100,
      cogs: Math.round(s.cogs * 100) / 100,
      gross_margin: Math.round(grossMargin * 100) / 100,
      margin_pct: Math.round(marginPct * 10000) / 100,
      revenue_share_pct: Math.round(revenueSharePct * 10000) / 100,
      avg_unit_price: s.units_sold > 0 ? Math.round(s.revenue / s.units_sold * 100) / 100 : 0,
    };
  })
  .sort((a, b) => b.revenue - a.revenue)
  .map(s => ({ json: s }));

// Convert the Generate Summary output into a markdown file
const item = $input.first();
const text = item.json.summary_text || '';

return [{
  json: { filename: 'summary.md' },
  binary: {
    data: {
      data: Buffer.from(text, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'summary.md',
    },
  },
}];

// Gate: only forward the run that has the full reconciled dataset.
// Reconcile fires multiple times due to multi-input; most runs return empty
// or small batches. Only the run with >5 items is the real data.
const items = $input.all();
if (items.length < 5) return [];
return items;
